(async () => {
      const run = await tick()
      if (cancelled || !run) return
      if (isGeneratingStatus(run.status)) {
        pollRef.current = setInterval(() => {
          void tick()
        }, POLL_INTERVAL_MS)
      }
    })

(async () => {
