(async () => {
      try {
        const result = await acceptInvite(token)
        if (result.status === 'pending') {
          setView('pending')
          return
        }
        navigate('/dashboard', {
          replace: true,
          state: { toast: 'Bạn đã tham gia project' },
        })
      } catch (err) {
        if (isAxiosError(err)) {
          const detail = (err.response?.data as { detail?: unknown } | undefined)?.detail
          if (err.response?.status === 410) {
            if (detail === 'Invitation already used') {
              setView('used')
              return
            }
            setView('expired')
            return
          }
          if (err.response?.status === 409) {
            const msg = typeof detail === 'string' ? detail : null
            if (msg?.includes('đang chờ')) {
              setView('pending')
              return
            }
            showSuccessToast('Bạn đã là thành viên của project này')
            navigate('/dashboard', { replace: true })
            return
          }
          const message =
            typeof detail === 'string' ? detail : 'Không thể chấp nhận lời mời'
          setErrorDetail(message)
          setView('error')
          showErrorToast(message)
          return
        }
        setErrorDetail('Không thể chấp nhận lời mời')
        setView('error')
        showErrorToast('Không thể chấp nhận lời mời')
      }
    })

(async () => {
      if (!projectId) return
      if (!canFetchCustom) {
        setLoading(false)
        setError(null)
        setData(null)
        setCustomHint('Chọn ngày bắt đầu và kết thúc để xem analytics.')
        return
      }
      if (range === 'custom' && fromDate > toDate) {
        setLoading(false)
        setData(null)
        setCustomHint(null)
        setError('Ngày bắt đầu phải trước hoặc bằng ngày kết thúc.')
        return
      }
      setCustomHint(null)
      setLoading(true)
      setError(null)
      try {
        const fromIso = range === 'custom' && fromDate ? `${fromDate}T00:00:00Z` : undefined
        const toIso = range === 'custom' && toDate ? `${toDate}T23:59:59Z` : undefined
        const result = await getProjectAnalytics(projectId, range, fromIso, toIso, {
          signal: ac.signal,
        })
        if (ac.signal.aborted) return
        setData(result)
      } catch (err) {
        if (ac.signal.aborted) return
        setData(null)
        setError(messageFromUnknown(err))
      } finally {
        if (!ac.signal.aborted) setLoading(false)
      }
    })

(async () => {
      if (token) {
        setAuthToken(token)
        try {
          await authApi.getMe(token)
          window.location.replace('/dashboard')
        } catch {
          setAuthToken(null)
          setErrorMessage('Could not verify your session. Please sign in again.')
          setPhase('error')
          window.setTimeout(() => {
            window.location.replace('/login?error=github_failed')
          }, 1800)
        }
        return
      }

      const reason = error ?? 'github_failed'
      window.location.replace(`/login?error=${encodeURIComponent(reason)}`)
    })

(async () => {
      if (!id) {
        setError('Project ID is missing from URL.')
        setLoading(false)
        return
      }
      try {
        setLoading(true)
        setError(null)
        const [response, project] = await Promise.all([
          getConstitution(id),
          currentProject?.id === id
            ? Promise.resolve(currentProject)
            : getProject(id).catch(() => null),
        ])
        if (!cancelled) {
          setContent(response.content)
          initialContentRef.current = response.content
          setLastSavedAt(response.updated_at)
          setSaveState('idle')
          if (project && currentProject?.id !== id) setCurrentProject(project)
        }
      } catch (err) {
        if (!cancelled) setError(errorMessage(err))
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      setLoading(true)
      setError(null)
      try {
        const dashboard = await getDashboard({ signal: ac.signal })
        if (ac.signal.aborted) return
        setData(dashboard)
      } catch (err) {
        if (ac.signal.aborted) return
        setError(messageFromUnknown(err))
      } finally {
        if (!ac.signal.aborted) setLoading(false)
      }
    })

(async () => {
      try {
        const data = await getDeployment(projectId, deploymentId)
        if (!cancelled) setDep(data)
      } catch (err) {
        if (!cancelled) setError(msgFromError(err))
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      try {
        const data = await listDeployments(projectId)
        if (!cancelled) setDeps(data)
      } catch (err) {
        if (!cancelled) {
          const msg = isAxiosError(err)
            ? ((err.response?.data as { detail?: string })?.detail ?? err.message)
            : (err instanceof Error ? err.message : 'Error')
          setError(msg)
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })

(async () => {
      const ok = await probeAuthToken()
      if (cancelled) return
      setChecking(false)
      if (ok) navigate('/dashboard', { replace: true })
    })

(async () => {
      try {
        const data = await listPipelineRuns(projectId)
        if (!cancelled) setRuns(data)
      } catch (err) {
        if (!cancelled) {
          const msg = isAxiosError(err)
            ? ((err.response?.data as { detail?: string })?.detail ?? err.message)
            : (err instanceof Error ? err.message : 'Error loading pipelines')
          setError(msg)
        }
      } finally {
        if (!cancelled) setLoading(false)
      }
    })
